@app.route('/issue-test-token', methods=['POST'])
def issue_test_token():
    data = request.get_json()
    if not data or 'user_id' not in data:
        return jsonify({"error": "user_id is required"}), 400

    user_id = data['user_id']
    import uuid
    new_token_value = str(uuid.uuid4())

    expires_at = datetime.utcnow() + timedelta(hours=1)

    new_token = AccessToken(token=new_token_value, user_id=user_id, expires_at=expires_at)
    db.session.add(new_token)
    db.session.commit()

    return jsonify({
        "message": "Test token issued successfully",
        "access_token": new_token_value,
        "token_type": "Bearer",
        "expires_in": 3600,
        "user_id": user_id
    }), 201

